  /**
   * 题库辅助工具类 (提供前端开发的高效调用方法)
   */
  const QuizHelper = {
    /**
     * 获取所有数据
     */
    getAllData: () => quizData,

    /**
     * 将选择题的字母答案 (如 "C") 转换为选项的数组索引 (2)
     * @param {string} letter - A, B, C, D
     * @returns {number} 索引号
     */
    letterToIndex: (letter) => {
      const charCode = letter.toUpperCase().charCodeAt(0);
      return charCode >= 65 && charCode <= 68 ? charCode - 65 : -1;
    },

    /**
     * 随机打乱数组（Fisher-Yates 算法），用于考题乱序
     * @param {Array} array - 原数组
     * @returns {Array} 打乱后的新数组
     */
    shuffleArray: (array) => {
      const newArray = [...array];
      for (let i = newArray.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [newArray[i], newArray[j]] = [newArray[j], newArray[i]];
      }
      return newArray;
    }
  };

  // 导出数据和工具类
  return {
    data: quizData,
    helper: QuizHelper
  };
